// Browser entry point. Boots the WebGPU visualizer, wires the audio sources
// (file / mic / tab), and drives a lightweight collapsible diagnostics panel.
//
// The `./pm_web/*` module is generated by `wasm-pack` (see package.json) and is
// git-ignored.
import init, {
  run,
  webgpu_supported,
  get_diagnostics,
  set_mouse,
  set_shader_source,
  midi_handle,
  midi_import,
  midi_export,
  midi_registry_json,
  midi_mappings_json,
  midi_set_mapping_field,
  midi_target_value,
  midi_take_actions,
  midi_take_updates,
} from './pm_web/pm_web.js';
import { AudioEngine } from './audio';
import { ShaderConsole } from './shader-console';
import { ControlsPanel } from './controls';
import { LayerPanel } from './layers';
import { EffectRack } from './effects-ui';
import { Recorder, WakeLock, toggleFullscreen } from './output';
import { copyShareUrl, loadFromUrl } from './share';
import { MidiManager } from './midi';
import { MidiPanel } from './midi-ui';

const MIDI_KEY = 'pm-web-midi-v1';

let controlsPanel: ControlsPanel | null = null;
let layerPanel: LayerPanel | null = null;
let effectRack: EffectRack | null = null;
let midiPanel: MidiPanel | null = null;
const recorder = new Recorder();

const canvas = document.getElementById('viz') as HTMLCanvasElement;

function resize(): void {
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  const w = Math.max(1, Math.floor(canvas.clientWidth * dpr));
  const h = Math.max(1, Math.floor(canvas.clientHeight * dpr));
  if (canvas.width !== w) canvas.width = w;
  if (canvas.height !== h) canvas.height = h;
}

function showFallback(detail?: string): void {
  if (detail) document.getElementById('fallback-msg')!.textContent = detail;
  document.getElementById('fallback')!.classList.add('show');
}

const $ = (id: string) => document.getElementById(id)!;

function setStatus(msg: string): void {
  $('audio-status').textContent = msg;
}

// --- Audio wiring ---------------------------------------------------------

const engine = new AudioEngine();

function wireAudioUI(): void {
  const fileInput = $('file-input') as HTMLInputElement;
  const transport = $('file-transport');
  const playPause = $('file-playpause') as HTMLButtonElement;
  const seek = $('file-seek') as HTMLInputElement;
  const loop = $('file-loop') as HTMLInputElement;

  fileInput.addEventListener('change', async () => {
    const file = fileInput.files?.[0];
    if (!file) return;
    try {
      const el = await engine.addFile(file);
      transport.style.display = 'flex';
      playPause.textContent = 'Pause';
      el.addEventListener('timeupdate', () => {
        if (el.duration) seek.value = String((el.currentTime / el.duration) * 1000);
      });
      el.addEventListener('play', () => (playPause.textContent = 'Pause'));
      el.addEventListener('pause', () => (playPause.textContent = 'Play'));
      setStatus(`Playing file: ${file.name}`);
    } catch (e) {
      setStatus(`File error: ${errMsg(e)}`);
    }
  });

  playPause.addEventListener('click', () => {
    const el = engine.fileElement();
    if (!el) return;
    if (el.paused) void el.play();
    else el.pause();
  });
  seek.addEventListener('input', () => {
    const el = engine.fileElement();
    if (el && el.duration) el.currentTime = (Number(seek.value) / 1000) * el.duration;
  });
  loop.addEventListener('change', () => {
    const el = engine.fileElement();
    if (el) el.loop = loop.checked;
  });

  $('mic-btn').addEventListener('click', async () => {
    if (engine.hasSource('mic')) {
      engine.removeSource('mic');
      setStatus('Microphone stopped');
      return;
    }
    try {
      await engine.enableMic();
      setStatus('Microphone active (not monitored to output)');
    } catch (e) {
      setStatus(`Mic error: ${errMsg(e)}`);
    }
  });

  $('tab-btn').addEventListener('click', async () => {
    if (engine.hasSource('display')) {
      engine.removeSource('display');
      setStatus('Tab/system capture stopped');
      return;
    }
    try {
      await engine.enableDisplay();
      setStatus('Capturing tab/system audio');
    } catch (e) {
      setStatus(`Capture error: ${errMsg(e)}`);
    }
  });

  ($('master-gain') as HTMLInputElement).addEventListener('input', (e) => {
    engine.setMasterGain(Number((e.target as HTMLInputElement).value));
  });

  engine.onSourcesChanged = () => {
    ($('mic-btn') as HTMLButtonElement).classList.toggle('on', engine.hasSource('mic'));
    ($('tab-btn') as HTMLButtonElement).classList.toggle('on', engine.hasSource('display'));
    if (!engine.fileElement()) transport.style.display = 'none';
  };

  $('diag-toggle').addEventListener('click', () => $('diag').classList.toggle('collapsed'));

  document.addEventListener('visibilitychange', () => {
    if (!document.hidden) void engine.resume();
  });
}

function errMsg(e: unknown): string {
  return e instanceof Error ? e.message : String(e);
}

// --- Shader console + render-source selector ------------------------------

function wireUI(): void {
  controlsPanel = new ControlsPanel($('controls-host'));

  const shaderConsole = new ShaderConsole($('console-host'));
  shaderConsole.onControls = (controls) => controlsPanel?.buildUserControls(controls);

  let selectedLayer: number | null = null;
  const lp = new LayerPanel($('layers-host'));
  layerPanel = lp;
  const er = new EffectRack($('effects-host'), () => selectedLayer);
  effectRack = er;
  er.onChanged = () => lp.save();

  layerPanel.onSelect = (kind, shader, layerId) => {
    selectedLayer = layerId;
    er.refresh();
    if (kind === 'shader') {
      shaderConsole.loadLayer(shader.source, shader.mode);
      controlsPanel?.buildUserControls(shader.controls);
    } else {
      controlsPanel?.buildUserControls([]);
    }
  };

  // Console and Layers both dock on the left — keep them mutually exclusive.
  $('console-btn').addEventListener('click', () => {
    $('console').classList.toggle('open');
    $('layers').classList.remove('open');
  });
  $('layers-btn').addEventListener('click', () => {
    $('layers').classList.toggle('open');
    $('console').classList.remove('open');
  });
  // Controls, Effects, and MIDI all dock on the right — mutually exclusive.
  const rightPanels = ['controls', 'effects', 'midi'];
  const openRight = (id: string) => {
    const wasOpen = $(id).classList.contains('open');
    rightPanels.forEach((p) => $(p).classList.remove('open'));
    if (!wasOpen) $(id).classList.add('open');
  };
  $('controls-btn').addEventListener('click', () => openRight('controls'));
  $('effects-btn').addEventListener('click', () => openRight('effects'));
  $('midi-btn').addEventListener('click', () => openRight('midi'));

  // MIDI performance control (Phase 8b).
  const midiManager = new MidiManager();
  midiPanel = new MidiPanel($('midi-host'), midiManager);
  midiPanel.onChange = saveMidi;

  wireOutput();
}

// --- MIDI persistence + app-action dispatch -------------------------------

let midiSaveTimer = 0;
/** Persist mappings (debounced — mapping edits are user-paced, never per-message). */
function saveMidi(): void {
  clearTimeout(midiSaveTimer);
  midiSaveTimer = window.setTimeout(() => {
    try {
      localStorage.setItem(MIDI_KEY, midi_export());
    } catch {
      /* storage unavailable */
    }
  }, 200);
}

function toggleRecord(): void {
  recorder.toggle(canvas, engine.captureAudioStream());
}

/** Dispatch app-side MIDI actions (queued in Rust, decoupled from buttons) and
 *  reflect MIDI-driven values into whichever side panels are open. */
function midiTick(): void {
  try {
    const actions: string[] = JSON.parse(midi_take_actions());
    for (const a of actions) {
      if (a === 'record.toggle') toggleRecord();
      // future: scene.next / scene.prev / fullscreen …
    }
  } catch {
    /* ignore */
  }
  try {
    const u = JSON.parse(midi_take_updates()) as { values: unknown[]; bools: unknown[] };
    if (u.values.length || u.bools.length) {
      if ($('layers').classList.contains('open')) layerPanel?.syncValues();
      if ($('effects').classList.contains('open')) effectRack?.syncValues();
    }
  } catch {
    /* ignore */
  }
  midiPanel?.tick();
}

// --- Output & sharing: share URL, recording, fullscreen, wake lock --------

function wireOutput(): void {
  $('share-btn').addEventListener('click', async () => {
    setStatus(await copyShareUrl());
  });

  const recBtn = $('rec-btn') as HTMLButtonElement;
  recorder.onState = (on) => {
    recBtn.classList.toggle('on', on);
    recBtn.textContent = on ? '■ Stop' : 'Rec';
    setStatus(on ? 'Recording…' : 'Recording saved');
  };
  recBtn.addEventListener('click', toggleRecord);

  $('full-btn').addEventListener('click', () => void toggleFullscreen(canvas));

  const wake = new WakeLock();
  const wakeBtn = $('wake-btn') as HTMLButtonElement;
  if (!wake.supported) wakeBtn.style.display = 'none';
  wake.onState = (held) => wakeBtn.classList.toggle('on', held);
  wakeBtn.addEventListener('click', () => void wake.toggle());
}

// --- iMouse pointer handling ----------------------------------------------

function wireMouse(): void {
  let down = false;
  let click: [number, number] = [0, 0];
  // Canvas backing pixels, bottom-left origin (matches fragCoord after flip).
  const coords = (e: PointerEvent): [number, number] => {
    const rect = canvas.getBoundingClientRect();
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    const x = (e.clientX - rect.left) * dpr;
    const y = (rect.height - (e.clientY - rect.top)) * dpr;
    return [x, y];
  };
  const send = (cur: [number, number]) => {
    // Shadertoy iMouse: xy = current pos; z/w = click origin, negated when up.
    set_mouse(cur[0], cur[1], down ? click[0] : -click[0], down ? click[1] : -click[1]);
  };
  canvas.addEventListener('pointerdown', (e) => {
    down = true;
    click = coords(e);
    send(click);
  });
  canvas.addEventListener('pointermove', (e) => {
    if (down) send(coords(e));
  });
  window.addEventListener('pointerup', () => (down = false));
  canvas.addEventListener('pointerleave', () => (down = false));
}

// --- Diagnostics panel ----------------------------------------------------

function bar(v: number): string {
  const pct = Math.max(0, Math.min(1, v)) * 100;
  return `<span class="bar"><span style="width:${pct.toFixed(0)}%"></span></span>`;
}

function updateDiagnostics(): void {
  let d: Record<string, number | boolean> = {};
  try {
    d = JSON.parse(get_diagnostics());
  } catch {
    /* wasm not ready */
  }
  const s = engine.status();
  const rows: [string, string][] = [
    ['layers', `${d.enabledCount ?? 0}/${d.layerCount ?? 0} on · ${d.shaderCount ?? 0} shader`],
    ['iTime', `${((d.time as number) ?? 0).toFixed(2)} s`],
    ['speed', `${((d.scale as number) ?? 1).toFixed(2)}× ${d.paused ? '(paused)' : ''}`],
    ['frame', String(d.frame ?? 0)],
    ['resolution', `${d.width ?? 0}×${d.height ?? 0}`],
    ['BPM', `${((d.bpm as number) ?? 0).toFixed(0)} ${d.tempoManual ? '(man)' : '(auto)'}`],
    ['beat', `${bar(d.beatPulse as number)} phase ${((d.beatPhase as number) ?? 0).toFixed(2)}`],
    ['crossOriginIsolated', String(self.crossOriginIsolated === true)],
    ['transport', s.shared ? 'SharedArrayBuffer' : 'postMessage (fallback)'],
    ['AudioContext', s.contextState],
    ['sampleRate', `${d.sampleRate || s.sampleRate || 0} Hz`],
    ['sources', s.sources.join(', ') || '(none)'],
    ['channels', String(d.channels ?? 0)],
    ['ring fill', `${(((d.ringFill as number) ?? 0) * 100).toFixed(0)}%`],
    ['overruns', String(d.overruns ?? 0)],
    ['underruns', String(d.underruns ?? 0)],
    ['PCM consumed', String(d.consumed ?? 0)],
    ['bass', `${bar(d.bass as number)} ${((d.bass as number) ?? 0).toFixed(2)}`],
    ['mid', `${bar(d.mid as number)} ${((d.mid as number) ?? 0).toFixed(2)}`],
    ['treb', `${bar(d.treb as number)} ${((d.treb as number) ?? 0).toFixed(2)}`],
    ['vol', `${bar(d.vol as number)} ${((d.vol as number) ?? 0).toFixed(2)}`],
  ];
  $('diag-body').innerHTML = rows
    .map(([k, v]) => `<div class="row"><span class="k">${k}</span><span class="v">${v}</span></div>`)
    .join('');
  controlsPanel?.showBpm((d.bpm as number) ?? 0, Boolean(d.tempoManual));
}

// --- Boot -----------------------------------------------------------------

async function boot(): Promise<void> {
  resize();
  window.addEventListener('resize', resize);

  if (!('gpu' in navigator)) {
    showFallback();
    return;
  }
  await init();
  if (!webgpu_supported()) {
    showFallback();
    return;
  }
  try {
    await run('viz');
  } catch (e) {
    console.error(e);
    showFallback(`WebGPU initialization failed: ${errMsg(e)}`);
    return;
  }

  // Renderer is up. Audio is optional and must not affect it.
  const ui = $('ui');
  ui.style.display = 'flex';
  // The control bar wraps on narrow widths; keep the side panels docked exactly
  // above it (not under a hardcoded height) so they never cover the bar.
  const syncBarHeight = () =>
    document.documentElement.style.setProperty('--bar-h', `${ui.offsetHeight}px`);
  new ResizeObserver(syncBarHeight).observe(ui);
  syncBarHeight();
  wireAudioUI();
  wireUI();
  wireMouse();

  // A shared scene in the URL fragment overrides the locally-restored scene.
  if (await loadFromUrl()) {
    layerPanel?.refresh();
    layerPanel?.emitSelect();
    layerPanel?.save();
    setStatus('Loaded shared scene from URL');
  }

  // Restore saved MIDI mappings (kept globally, not per-scene).
  try {
    const savedMidi = localStorage.getItem(MIDI_KEY);
    if (savedMidi) midi_import(savedMidi);
  } catch {
    /* storage unavailable */
  }

  // Dev/test-only MIDI injection: forwards to the SAME handler real MIDI uses
  // (no privileged path). Enabled under Vite dev or an explicit ?miditest flag,
  // so the Playwright harness can synthesize messages without real hardware.
  const isDev = (import.meta as unknown as { env?: { DEV?: boolean } }).env?.DEV === true;
  if (isDev || location.search.includes('miditest')) {
    (window as unknown as Record<string, unknown>).__pmMidi = {
      inject: (device: string, status: number, d1: number, d2: number) => midi_handle(device, status, d1, d2),
      registry: () => midi_registry_json(),
      mappings: () => midi_mappings_json(),
      // Compile a shader into the selected layer (same export the console uses)
      // so tests can create a known control target without driving CodeMirror.
      compileSelected: (mode: number, src: string) => set_shader_source(mode, src),
      setField: (id: number, field: string, value: string) => midi_set_mapping_field(id, String(field), String(value)),
      value: (path: string) => JSON.parse(midi_target_value(path)),
    };
  }

  setInterval(updateDiagnostics, 200);
  setInterval(midiTick, 100);
}

void boot();
